it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
  const cells = [[0, 1], [1, 1], [0, 0]];
  const result = nextGeneration(cells);
  expect(result).toEqual(expect.arrayContaining([[1, 0]]));
});
